server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate /etc/ssl/certs/nginx-selfsigned.crt;
    ssl_certificate_key /etc/ssl/private/nginx-selfsigned.key;

    location / {
        root /var/www/main;
        index index.html;
    }

    location /dev/ {
        alias /var/www/dev/;
        index index.html;
    }
}

